<?php session_start(); require 'db.php'; if(!isset($_SESSION['user_id'])) exit; $pid=$_GET['id']; $post=$pdo->prepare("SELECT * FROM posts WHERE id=?"); $post->execute([$pid]); $p=$post->fetch(); if($p && $p['user_id']==$_SESSION['user_id']){ if($p['image_path']) @unlink($p['image_path']); $pdo->prepare("DELETE FROM posts WHERE id=?")->execute([$pid]); } header("Location: index.php"); ?>
